content:
{
  "sentences": [
    {
      "text": "今天天氣太熱了，我沒有精神。",
      "pinyin": "Jīntiān tiānqì tài rè le, wǒ méiyǒu jīngshén.",
      "pinyin_numeric": "jin1tian1 tian1qi4 tai4 re4 le0, wo3 mei2you3 jing1shen2.",
      "translation_en": "The weather is too hot today; I have no energy.",
      "translation_ko": "오늘 날씨가 너무 더워서 기운이 없어요."
    },
    {
      "text": "颱風要來了，我太緊張了。",
      "pinyin": "Táifēng yào lái le, wǒ tài jǐnzhāng le.",
      "pinyin_numeric": "tai2feng1 yao4 lai2 le0, wo3 tai4 jin3zhang1 le0.",
      "translation_en": "A typhoon is coming; I am too nervous.",
      "translation_ko": "태풍이 오려고 해서 너무 긴장돼요."
    },
    {
      "text": "下雨天路太滑了，要小心走路。",
      "pinyin": "Xiàyǔ tiān lù tài huá le, yào xiǎoxīn zǒulù.",
      "pinyin_numeric": "xia4yu3 tian1 lu4 tai4 hua2 le0, yao4 xiao3xin1 zou3lu4.",
      "translation_en": "The road is too slippery on rainy days; be careful when walking.",
      "translation_ko": "비 오는 날 길이 너무 미끄러우니까 조심해서 걸어야 해요."
    },
    {
      "text": "今天三十度，天氣太悶熱了，心情不好。",
      "pinyin": "Jīntiān sānshí dù, tiānqì tài mēnrè le, xīnqíng bù hǎo.",
      "pinyin_numeric": "jin1tian1 san1shi2 du4, tian1qi4 tai4 men1re4 le0, xin1qing2 bu4 hao3.",
      "translation_en": "It's 30 degrees today; the weather is too muggy, and I'm in a bad mood.",
      "translation_ko": "오늘은 30도인데 날씨가 너무 후덥지근해서 기분이 안 좋아요."
    },
    {
      "text": "晴天太陽太大了，我擔心會曬黑。",
      "pinyin": "Qíngtiān tàiyáng tài dà le, wǒ dānxīn huì shài hēi.",
      "pinyin_numeric": "qing2tian1 tai4yang2 tai4 da4 le0, wo3 dan1xin1 hui4 shai4 hei1.",
      "translation_en": "The sun is too strong on a sunny day; I'm worried about getting tanned.",
      "translation_ko": "맑은 날 태양이 너무 커서 검게 탈까 봐 걱정돼요."
    },
    {
      "text": "陰天風太大了，我覺得很冷。",
      "pinyin": "Yīntiān fēng tài dà le, wǒ juéde hěn lěng.",
      "pinyin_numeric": "yin1tian1 feng1 tai4 da4 le0, wo3 jue2de hen3 leng3.",
      "translation_en": "The wind is too strong on a cloudy day; I feel very cold.",
      "translation_ko": "흐린 날 바람이 너무 세서 매우 춥다고 느껴요."
    },
    {
      "text": "今天天氣太舒服了，我心情很好。",
      "pinyin": "Jīntiān tiānqì tài shūfu le, wǒ xīnqíng hěn hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 tai4 shu1fu0 le0, wo3 xin1qing2 hen3 hao3.",
      "translation_en": "The weather is too comfortable today; I'm in a great mood.",
      "translation_ko": "오늘 날씨가 너무 쾌적해서 기분이 아주 좋아요."
    },
    {
      "text": "下雨了，我沒帶傘，壓力太大了。",
      "pinyin": "Xiàyǔ le, wǒ méi dài sǎn, yālì tài dà le.",
      "pinyin_numeric": "xia4yu3 le0, wo3 mei2 dai4 san3, ya1li4 tai4 da4 le0.",
      "translation_en": "It's raining, and I didn't bring an umbrella; the pressure is too great.",
      "translation_ko": "비가 오는데 우산을 안 가져와서 스트레스가 너무 커요."
    },
    {
      "text": "颱風天風太大了，我太擔心了。",
      "pinyin": "Táifēng tiān fēng tài dà le, wǒ tài dānxīn le.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 tai4 da4 le0, wo3 tai4 dan1xin1 le0.",
      "translation_en": "The wind is too strong on a typhoon day; I'm too worried.",
      "translation_ko": "태풍이 오는 날 바람이 너무 세서 너무 걱정돼요."
    },
    {
      "text": "今天溫度二十度，天氣太涼快了，我很開心。",
      "pinyin": "Jīntiān wēndù èrshí dù, tiānqì tài liángkuai le, wǒ hěn kāixīn.",
      "pinyin_numeric": "jin1tian1 wen1du4 er4shi2 du4, tian1qi4 tai4 liang2kuai0 le0, wo3 hen3 kai1xin1.",
      "translation_en": "It's 20 degrees today; the weather is too cool, and I'm very happy.",
      "translation_ko": "오늘 기온이 20도인데 날씨가 너무 시원해서 아주 기뻐요."
    }
  ]
}
